#include <iostream>
#include <string>

class Teacher
{
    std::string m_name;

public:
    Teacher(std::string name) : m_name{ name } {}
    const std::string& getName() const { return m_name; }
};

class Department
{
    std::string m_name;
    const Teacher& m_lead;

public:
    Department(std::string name, const Teacher& lead)
        : m_name{ name }
        , m_lead{ lead }
    {
    }

    void print() const
    {
        std::cout << m_name << " lead: " << m_lead.getName() << '\n';
    }
};

int main()
{
    std::string teacherName{};
    std::string dept1Name{};
    std::string dept2Name{};
    std::cin >> teacherName >> dept1Name >> dept2Name;

    Teacher t{ teacherName };

    {
        Department d1{ dept1Name, t };
        Department d2{ dept2Name, t };
        d1.print();
        d2.print();
    }

    std::cout << t.getName() << " still exists" << '\n';

    return 0;
}
